patch:
diff --git a/llvm/lib/Analysis/LoopAccessAnalysis.cpp b/llvm/lib/Analysis/LoopAccessAnalysis.cpp
index cf3bb6a8eae1..f9499c647028 100644
--- a/llvm/lib/Analysis/LoopAccessAnalysis.cpp
+++ b/llvm/lib/Analysis/LoopAccessAnalysis.cpp
@@ -420,8 +420,6 @@ bool RuntimeCheckingPtrGroup::addPointer(unsigned Index, const SCEV *Start,
                                          ScalarEvolution &SE) {
   assert(AddressSpace == AS &&
          "all pointers in a checking group must be in the same address space");
-
-  // Compare the starts and ends with the known minimum and maximum
   // of this set. We need to know how we compare against the min/max
   // of the set in order to be able to emit memchecks.
   const SCEV *Min0 = getMinFromExprs(Start, Low, &SE);
@@ -549,6 +547,9 @@ void RuntimePointerChecking::groupChecks(

           TotalComparisons++;

+          unsigned PtrAS = Pointers[Pointer].PointerValue->getType()->getPointerAddressSpace();
+          if (Group.AddressSpace != PtrAS)
+            continue;
           if (Group.addPointer(Pointer, *this)) {
             Merged = true;
             break;
@@ -1210,9 +1211,15 @@ bool AccessAnalysis::canCheckPtrAtRT(

     SmallVector<std::pair<MemAccessInfo, Type *>, 4> Retries;

+
+
     // First, count how many write and read accesses are in the alias set. Also
     // collect MemAccessInfos for later.
     SmallVector<MemAccessInfo, 4> AccessInfos;
+    SmallDenseSet<unsigned, 4> AliasSetAddressSpaces;
+    /* Detect mixed address spaces within the same alias set which we cannot
+       reliably check at runtime. In such case, mark bounds as uncomputable. */
+    
     for (const Value *ConstPtr : ASPointers) {
       Value *Ptr = const_cast<Value *>(ConstPtr);
       bool IsWrite = Accesses.count(MemAccessInfo(Ptr, true));
@@ -1221,9 +1228,26 @@ bool AccessAnalysis::canCheckPtrAtRT(
       else
         ++NumReadPtrChecks;
       AccessInfos.emplace_back(Ptr, IsWrite);
+      AliasSetAddressSpaces.insert(Ptr->getType()->getPointerAddressSpace());
     }

     // We do not need runtime checks for this alias set, if there are no writes
+    // Mixed address spaces within this alias set cannot be reliably checked at runtime.
+    if (AliasSetAddressSpaces.size() > 1) {
+      CanDoAliasSetRT = false;
+      CanDoRT = false;
+      if (!AccessInfos.empty())
+        UncomputablePtr = AccessInfos.front().getPointer();
+    }
+    // If there are mixed address spaces in this alias set, force failure to
+    // identify array bounds for runtime checking.
+    if (AliasSetAddressSpaces.size() > 1) {
+      CanDoAliasSetRT = false;
+      if (!AccessInfos.empty())
+        UncomputablePtr = AccessInfos.front().getPointer();
+      // Add a dummy retry to ensure NeedsAliasSetRTCheck is true.
+      Retries.emplace_back(AccessInfos.front(), *Accesses[AccessInfos.front()].begin());
+    }
     // or a single write and no reads.
     if (NumWritePtrChecks == 0 ||
         (NumWritePtrChecks == 1 && NumReadPtrChecks == 0)) {

